INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'overview', 'Overview > Full Name: National Institute of Technology Karnataka, Surathkal (NITK Surathkal).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'overview', 'Overview > Location: Surathkal, Mangalore, Karnataka 575025.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'fee_structure', 'Fee Structure > Hostel Fee for B.Tech/MCA/M.Tech/MBA/M.Sc/Ph.D at NITK Surathkal for 2025-26 batch.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'fee_structure', 'Fee Structure > Hostel Fee (New Admission): Hostel Admission Fee Rs 1,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'fee_structure', 'Fee Structure > Hostel Fee (New Admission) Establishment Charges: Maintenance Rs 120, Student Concession Fund Rs 150, Mess Concession Fund Rs 150, GOEM (General Amenities and Equipment Fund) Rs 550, Students Medical Relief Fund Rs 100, V.P. Fund Rs 250, Winner-cadre overhead Rs 1,000, Security Rs 20, Student Contingency Fund Rs 70, Games/T.A.S.K Fund Rs 70, Diwali Fund Rs 30, Hostel Day Celebrations Rs 70, Recreation committee (cultural event) Rs 130, Miscellaneous Rs 20.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'fee_structure', 'Fee Structure > Hostel Fee (New Admission) Total Fee Rs 3,900. Mess Advance Rs 22,000. Grand Total for new admission Rs 25,300.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'fee_structure', 'Fee Structure > Hostel Fee (Subsequent Semesters): Odd semester approximately Rs 34,310. Even semester approximately Rs 33,790.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'attendance', 'Attendance > Minimum 75% attendance required for end-semester exams at NITK Surathkal.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'attendance', 'Attendance > The 75% requirement can be relaxed up to 65% by the Director.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'attendance', 'Attendance > An extra 5% relaxation is possible beyond the 65% threshold.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'attendance', 'Attendance > Medical exigency can further relax attendance requirement to 50%.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Surathkal', 'attendance', 'Attendance > Students below 65% attendance are marked "Detained" and are not allowed to sit for the end-semester exam.');
